  1→import { PAPER_PRESETS } from '@/sheets/paper';
  2→import { projectPartToView, getPartExtents } from '../domain/viewProjection';
  3→
  4→const MARGIN = 15; // mm
  5→const TITLE_HEIGHT = 12; // mm
  6→const VIEW_GAP = 10; // mm
  7→const STROKE_WIDTH = 0.3;
  8→
  9→function getPartsBounds(parts, view) {
 10→  let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
 11→
 12→  for (const part of parts) {
 13→    if (part.type === 'dimension') continue;
 14→    const { svgX, svgY, svgWidth, svgHeight } = projectPartToView(part, view);
 15→    minX = Math.min(minX, svgX);
 16→    minY = Math.min(minY, svgY);
 17→    maxX = Math.max(maxX, svgX + svgWidth);
 18→    maxY = Math.max(maxY, svgY + svgHeight);
 19→  }
 20→
 21→  if (minX === Infinity) return { x: 0, y: 0, width: 0, height: 0 };
 22→  return { x: minX, y: minY, width: maxX - minX, height: maxY - minY };
 23→}
 24→
 25→function renderViewSvg(parts, view, offsetX, offsetY, scale) {
 26→  const lines = [];
 27→
 28→  for (const part of parts) {
 29→    if (part.type === 'dimension') continue;
 30→    const { svgX, svgY, svgWidth, svgHeight } = projectPartToView(part, view);
 31→    const isSubtractive = part.type === 'cutout' || part.type === 'hole';
 32→
 33→    const x = offsetX + svgX * scale;
 34→    const y = offsetY + svgY * scale;
 35→    const w = svgWidth * scale;
 36→    const h = svgHeight * scale;
 37→
 38→    if (part.type === 'hole' && view === 'top') {
 39→      lines.push(
 40→        `<ellipse cx="${x + w / 2}" cy="${y + h / 2}" rx="${w / 2}" ry="${h / 2}" ` +
 41→        `fill="none" stroke="#333" stroke-width="${STROKE_WIDTH}" ${isSubtractive ? 'stroke-dasharray="1 0.8"' : ''}/>`
 42→      );
 43→    } else {
 44→      lines.push(
 45→        `<rect x="${x}" y="${y}" width="${w}" height="${h}" ` +
 46→        `fill="none" stroke="#333" stroke-width="${STROKE_WIDTH}" ${isSubtractive ? 'stroke-dasharray="1 0.8"' : ''}/>`
 47→      );
 48→    }
 49→  }
 50→
 51→  return lines.join('\n');
 52→}
 53→
 54→export function exportSketchSvg(project) {
 55→  const paper = PAPER_PRESETS.A4_LANDSCAPE;
 56→  const pageW = paper.width;
 57→  const pageH = paper.height;
 58→
 59→  const renderParts = project.parts.filter((p) => p.type !== 'dimension');
 60→  if (renderParts.length === 0) return null;
 61→
 62→  const views = ['top', 'front', 'side'];
 63→  const viewLabels = { top: 'Top View', front: 'Front View', side: 'Side View' };
 64→
 65→  // Calculate bounds for each view
 66→  const boundsList = views.map((v) => getPartsBounds(renderParts, v));
 67→
 68→  // Available area for 3 views side by side
 69→  const availW = pageW - 2 * MARGIN;
 70→  const availH = pageH - 2 * MARGIN - TITLE_HEIGHT - VIEW_GAP;
 71→
 72→  // Each view gets 1/3 of width
 73→  const viewSlotW = (availW - 2 * VIEW_GAP) / 3;
 74→  const viewSlotH = availH;
 75→
 76→  // Find uniform scale that fits all views
 77→  let scale = Infinity;
 78→  for (let i = 0; i < views.length; i++) {
 79→    const b = boundsList[i];
 80→    if (b.width > 0) scale = Math.min(scale, viewSlotW / b.width);
 81→    if (b.height > 0) scale = Math.min(scale, viewSlotH / b.height);
 82→  }
 83→  if (!isFinite(scale) || scale <= 0) scale = 0.1;
 84→
 85→  // Build SVG
 86→  let svgContent = '';
 87→  svgContent += `<rect x="0" y="0" width="${pageW}" height="${pageH}" fill="white"/>\n`;
 88→
 89→  // Title block
 90→  svgContent += `<text x="${pageW / 2}" y="${MARGIN + 6}" text-anchor="middle" font-family="sans-serif" font-size="5" font-weight="bold" fill="#333">${project.name || 'Untitled'}</text>\n`;
 91→  svgContent += `<text x="${pageW - MARGIN}" y="${pageH - 4}" text-anchor="end" font-family="sans-serif" font-size="3" fill="#999">${new Date().toLocaleDateString()}</text>\n`;
 92→
 93→  // Render each view
 94→  for (let i = 0; i < views.length; i++) {
 95→    const view = views[i];
 96→    const b = boundsList[i];
 97→    const slotX = MARGIN + i * (viewSlotW + VIEW_GAP);
 98→    const slotY = MARGIN + TITLE_HEIGHT + VIEW_GAP;
 99→
100→    // Center within slot
101→    const renderedW = b.width * scale;
102→    const renderedH = b.height * scale;
103→    const offsetX = slotX + (viewSlotW - renderedW) / 2 - b.x * scale;
104→    const offsetY = slotY + (viewSlotH - renderedH) / 2 - b.y * scale;
105→
106→    // View label
107→    svgContent += `<text x="${slotX + viewSlotW / 2}" y="${slotY - 2}" text-anchor="middle" font-family="sans-serif" font-size="3.5" fill="#666">${viewLabels[view]}</text>\n`;
108→
109→    // View border
110→    svgContent += `<rect x="${slotX}" y="${slotY}" width="${viewSlotW}" height="${viewSlotH}" fill="none" stroke="#ddd" stroke-width="0.2"/>\n`;
111→
112→    // Parts
113→    svgContent += renderViewSvg(renderParts, view, offsetX, offsetY, scale);
114→  }
115→
116→  // Page border
117→  svgContent += `<rect x="0.5" y="0.5" width="${pageW - 1}" height="${pageH - 1}" fill="none" stroke="#999" stroke-width="0.3"/>\n`;
118→
119→  const svg = `<?xml version="1.0" encoding="UTF-8"?>\n<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${pageW} ${pageH}" width="${pageW}mm" height="${pageH}mm">\n${svgContent}</svg>`;
120→
121→  return svg;
122→}
123→
124→export function downloadSketchSvg(project) {
125→  const svg = exportSketchSvg(project);
126→  if (!svg) return;
127→
128→  const blob = new Blob([svg], { type: 'image/svg+xml' });
129→  const url = URL.createObjectURL(blob);
130→  const a = document.createElement('a');
131→  a.href = url;
132→  a.download = `${project.name || 'sketch'}-sheet.svg`;
133→  document.body.appendChild(a);
134→  a.click();
135→  document.body.removeChild(a);
136→  URL.revokeObjectURL(url);
137→}
