.sidebar {
  background: var(--color-panel-bg);
  border-right: 1px solid var(--color-border);
  overflow-y: auto;
  padding: var(--space-lg);
  display: flex;
  flex-direction: column;
  gap: var(--space-lg);
}

.section {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
}

.sectionHeaderRow {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 2px 4px;
  border-bottom: 1px solid var(--color-workspace-sketch, #B8860B);
  padding-bottom: 6px;
}

.sectionTitle {
  font-family: var(--font-heading);
  font-size: 12px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--color-text-primary);
}

.count {
  margin-left: auto;
  font-size: 10px;
  color: var(--color-workspace-sketch, #B8860B);
  background: rgba(184, 134, 11, 0.1);
  padding: 0 5px;
  border-radius: 10px;
  line-height: 18px;
  font-weight: 700;
}

.addBtn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
  border-radius: var(--radius-sm);
  color: var(--color-text-secondary);
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  background: transparent;
  border: none;
  transition: background var(--duration-fast), color var(--duration-fast);
  flex-shrink: 0;
}

.addBtn:hover {
  background: rgba(0, 0, 0, 0.06);
  color: var(--color-workspace-sketch, #B8860B);
}

.addBtn:active {
  transform: scale(0.92);
}

.layerList {
  display: flex;
  flex-direction: column;
