  border-radius: 8px;
  line-height: 16px;
  flex-shrink: 0;
}

.layerActions {
  display: flex;
  align-items: center;
  gap: 2px;
  flex-shrink: 0;
  opacity: 0.5;
  transition: opacity var(--duration-fast);
}

.layerItem:hover .layerActions {
  opacity: 1;
}

.layerItemActive .layerActions {
  opacity: 0.8;
}

.layerActionBtn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 22px;
  height: 22px;
  border-radius: var(--radius-sm);
  background: transparent;
  border: none;
  color: var(--color-text-secondary);
  cursor: pointer;
  transition: background var(--duration-fast), color var(--duration-fast);
}

.layerActionBtn:hover {
  background: rgba(0, 0, 0, 0.06);
  color: var(--color-text-primary);
}

.layerActionBtn:active {
  transform: scale(0.9);
}

.layerActionBtn:disabled {
  opacity: 0.3;
  cursor: not-allowed;
}

.layerActionBtn:disabled:hover {
  background: transparent;
  color: var(--color-text-secondary);
}

.layerActionIcon {
  width: 14px;
  height: 14px;
  display: block;
}

.categoryBadge {
  font-size: 9px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--color-workspace-sketch, #B8860B);
  background: rgba(184, 134, 11, 0.1);
  padding: 1px 5px;
  border-radius: 8px;
  line-height: 16px;
  flex-shrink: 0;
}

