import { createDimension } from '../../domain/partModels';
import { viewToModelPosition } from '../../domain/viewProjection';
import { snapPoint } from '../snap';
import { SKETCH_GRID_MINOR } from '../../domain/defaults';

export function createDimensionHandler({ dispatch, editorDispatch, activeView, snapEnabled }) {
  return {
    onMouseDown(modelPos, e, toolState) {
      if (e.button !== 0) return;

      const pos = snapEnabled ? snapPoint(modelPos, SKETCH_GRID_MINOR) : modelPos;

      if (!toolState.firstPoint) {
        // First click - set start point
        editorDispatch({
          type: 'UPDATE_TOOL_STATE',
          payload: {
            firstPoint: { x: pos.x, y: pos.y },
          },
        });
        editorDispatch({
          type: 'SET_STATUS_MESSAGE',
          message: 'Click second point for dimension.',
        });
      } else {
        // Second click - create dimension
        const start3D = viewToModelPosition(toolState.firstPoint.x, toolState.firstPoint.y, activeView);
        const end3D = viewToModelPosition(pos.x, pos.y, activeView);

        const dim = createDimension({
          startPoint: start3D,
          endPoint: end3D,
          offset: 200,
        });

        dispatch({ type: 'PART_ADD', part: dim });

        editorDispatch({
          type: 'UPDATE_TOOL_STATE',
          payload: { firstPoint: null },
        });

        editorDispatch({
          type: 'SET_STATUS_MESSAGE',
          message: 'Dimension placed.',
        });
      }
    },

    onMouseMove() {},

    onMouseUp() {},

    onKeyDown(e) {
      if (e.key === 'Escape') {
        editorDispatch({
          type: 'UPDATE_TOOL_STATE',
          payload: { firstPoint: null },
        });
      }
    },

    getCursor() {
      return 'crosshair';
    },
  };
}

